DROP TABLE IF EXISTS `stock_analyses`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stock_analyses` (
  `id` int NOT NULL AUTO_INCREMENT,
  `company_id` int NOT NULL,
  `symbol` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_profitable` tinyint(1) NOT NULL,
  `total_trades` int NOT NULL,
  `winning_trades` int NOT NULL,
  `losing_trades` int NOT NULL,
  `win_rate` double NOT NULL,
  `avg_profit_pct` double NOT NULL,
  `avg_loss_pct` double NOT NULL,
  `total_return_pct` double NOT NULL,
  `max_drawdown_pct` double NOT NULL,
  `sharpe_ratio` double DEFAULT NULL,
  `current_signal` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `entry_price` double DEFAULT NULL,
  `stop_loss` double DEFAULT NULL,
  `target_1` double DEFAULT NULL,
  `target_2` double DEFAULT NULL,
  `rsi` double DEFAULT NULL,
  `macd` double DEFAULT NULL,
  `ema9` double DEFAULT NULL,
  `ema21` double DEFAULT NULL,
  `recommendation` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `analysed_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `stock_analyses_symbol_idx` (`symbol`),
  KEY `stock_analyses_analysed_at_idx` (`analysed_at`),
  KEY `stock_analyses_company_id_fkey` (`company_id`),
  CONSTRAINT `stock_analyses_company_id_fkey` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
