CREATE TABLE `stock_candles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `company_id` int NOT NULL,
  `symbol` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `open` double NOT NULL,
  `high` double NOT NULL,
  `low` double NOT NULL,
  `close` double NOT NULL,
  `volume` bigint NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `stock_candles_symbol_date_key` (`symbol`,`date`),
  KEY `stock_candles_symbol_idx` (`symbol`),
  KEY `stock_candles_date_idx` (`date`),
  KEY `stock_candles_company_id_fkey` (`company_id`),
  CONSTRAINT `stock_candles_company_id_fkey` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12298 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
